    `brand_guidelines_url` STRING COMMENT 'URL or document reference for the advertisers brand guidelines and creative specifications for activation materials.',
    `conflict_brands` STRING COMMENT 'Comma-separated list of competing brands or advertisers that cannot be simultaneously partnered due to category exclusivity or contractual restrictions.',
    `contract_renewal_date` DATE COMMENT 'Scheduled date for the next contract renewal discussion or expiration of current agreement.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the advertiser record was first created in the system.',
    `credit_rating` STRING COMMENT 'Credit rating assigned to the advertiser for financial risk assessment and payment terms determination.',
    `exclusivity_category` STRING COMMENT 'Product or service category for which the advertiser holds exclusivity rights, preventing competing brands in the same category.',
    `first_partnership_date` DATE COMMENT 'Date when the advertiser first entered into a sponsorship or partnership agreement with the organization.',
    `headquarters_address_line1` STRING COMMENT 'First line of the advertiser headquarters street address.',
    `headquarters_address_line2` STRING COMMENT 'Second line of the advertiser headquarters street address (suite, floor, building).',
    `headquarters_city` STRING COMMENT 'City where the advertiser headquarters is located.',
    `headquarters_country_code` STRING COMMENT 'Three-letter ISO country code for the advertiser headquarters location.',
    `headquarters_postal_code` STRING COMMENT 'Postal or ZIP code for the advertiser headquarters location.',
    `headquarters_state_province` STRING COMMENT 'State or province where the advertiser headquarters is located.',
    `industry_category` STRING COMMENT 'Primary industry vertical or sector the advertiser operates in (e.g., automotive, consumer goods, technology, financial services).',
    `is_active_partner` BOOLEAN COMMENT 'Boolean flag indicating whether the advertiser currently has one or more active sponsorship contracts.',
    `last_contract_date` DATE COMMENT 'Date of the most recent contract or agreement signed with the advertiser.',
    `logo_asset_url` STRING COMMENT 'URL or storage path to the advertisers official logo files for use in sponsorship activations and marketing materials.',
    `modified_by` STRING COMMENT 'Username or identifier of the user who last modified the advertiser record.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when the advertiser record was last modified.',
    `notes` STRING COMMENT 'Free-form notes and comments about the advertiser relationship, preferences, history, or special considerations.',
    `parent_company_name` STRING COMMENT 'Name of the parent or holding company if the advertiser is a subsidiary.',
    `payment_terms_days` STRING COMMENT 'Standard number of days allowed for payment of invoices (e.g., Net 30, Net 60).',
    `preferred_activation_channels` STRING COMMENT 'Comma-separated list of preferred marketing and activation channels for the advertiser (e.g., broadcast, digital, venue signage, social media, experiential).',
    `preferred_currency_code` STRING COMMENT 'Three-letter ISO currency code for the advertisers preferred billing and contract currency.',
    `primary_contact_email` STRING COMMENT 'Email address of the primary business contact for sponsorship communications and contract management.',
    `primary_contact_name` STRING COMMENT 'Full name of the primary business contact at the advertiser organization.',
    `primary_contact_phone` STRING COMMENT 'Primary phone number for reaching the advertiser contact.',
    `target_audience_demographics` STRING COMMENT 'Description of the advertisers target audience demographics and psychographics for alignment with sponsorship properties.',
    `tax_identification_number` STRING COMMENT 'Tax identification number or employer identification number for the advertiser organization.',
    `website_url` STRING COMMENT 'Primary website URL for the advertiser organization.',
    `created_by` STRING COMMENT 'Username or identifier of the user who created the advertiser record.',
    CONSTRAINT pk_advertiser PRIMARY KEY(`advertiser_id`)
) COMMENT 'Master reference table for advertiser. Referenced by advertiser_id.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`sponsorship`.`sponsor_contact` (
