    `address_line_1` STRING COMMENT 'First line of the business address for the sponsor contact (street address, building number).',
    `address_line_2` STRING COMMENT 'Second line of the business address for the sponsor contact (suite, floor, department).',
    `city` STRING COMMENT 'City where the sponsor contact is located.',
    `contact_status` STRING COMMENT 'Current status of the sponsor contact indicating availability and engagement level.',
