    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this sponsor contact record was last modified or updated.',
    `next_follow_up_date` DATE COMMENT 'Scheduled date for the next planned follow-up or touchpoint with this sponsor contact.',
