    `postal_code` STRING COMMENT 'Postal or ZIP code for the sponsor contacts business address.',
    `preferred_communication_method` STRING COMMENT 'The contacts preferred method of communication for sponsorship-related matters.',
    `relationship_strength_score` DECIMAL(18,2) COMMENT 'Quantitative score (0-100) representing the strength and quality of the relationship with this sponsor contact based on engagement frequency, responsiveness, and partnership satisfaction.',
    `secondary_email_address` STRING COMMENT 'Alternative email address for the sponsor contact.',
    `state_province` STRING COMMENT 'State or province where the sponsor contact is located.',
    `time_zone` STRING COMMENT 'Time zone of the sponsor contact for scheduling meetings and communications (e.g., America/New_York, Europe/London).',
    CONSTRAINT pk_sponsor_contact PRIMARY KEY(`sponsor_contact_id`)
