    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this property record was first created in the system.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for sponsorship pricing.',
    `property_description` STRING COMMENT 'Detailed description of the property including its sponsorship value proposition and audience reach.',
    `digital_activation_available` BOOLEAN COMMENT 'Indicates whether digital platform activation opportunities are available.',
    `digital_impressions` BIGINT COMMENT 'Estimated digital and social media impressions per occurrence or campaign period.',
    `effective_date` DATE COMMENT 'Date when this property became available for sponsorship or when current configuration became effective.',
    `estimated_annual_reach` BIGINT COMMENT 'Estimated total audience reach per year across all channels (live, broadcast, digital).',
    `estimated_live_attendance` STRING COMMENT 'Average or expected live in-person attendance per event occurrence.',
    `exclusivity_available` BOOLEAN COMMENT 'Indicates whether category exclusivity is available for this property.',
    `expiration_date` DATE COMMENT 'Date when this property will no longer be available for sponsorship or when current configuration expires.',
    `frequency_per_year` STRING COMMENT 'Number of times this property occurs annually (e.g., 52 for weekly show, 1 for annual event).',
    `geographic_market` STRING COMMENT 'Primary geographic market or region for this property.',
    `inventory_units_available` STRING COMMENT 'Total number of sponsorship inventory units available for this property (e.g., signage spots, ad slots).',
    `inventory_units_sold` STRING COMMENT 'Number of sponsorship inventory units currently sold or committed.',
    `jersey_sponsorship_available` BOOLEAN COMMENT 'Indicates whether jersey or uniform branding is available for this property.',
    `media_value_multiplier` DECIMAL(18,2) COMMENT 'Multiplier used to calculate equivalent media value for sponsorship exposure on this property.',
    `modified_by` STRING COMMENT 'User or system identifier that last modified this property record.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this property record was last modified.',
    `naming_rights_available` BOOLEAN COMMENT 'Indicates whether naming rights sponsorship is available for this property.',
    `property_category` STRING COMMENT 'Business category segmenting the property for sponsorship packaging and pricing.',
    `property_code` STRING COMMENT 'Unique business identifier or code for the property used in contracts and inventory systems.',
    `property_name` STRING COMMENT 'The official name of the sponsorable property (e.g., WrestleMania, Monday Night Raw, Royal Rumble Arena).',
    `property_status` STRING COMMENT 'Current lifecycle status of the property in the sponsorship inventory.',
    `property_tier` STRING COMMENT 'Sponsorship tier or premium level assigned to the property for pricing and packaging.',
    `property_type` STRING COMMENT 'Classification of the sponsorable property type.',
    `season_end_date` DATE COMMENT 'End date of the season or active period for this property.',
    `season_start_date` DATE COMMENT 'Start date of the season or active period for this property.',
    `target_demographic` STRING COMMENT 'Primary target audience demographic profile for this property (e.g., Males 18-34, Families).',
    `created_by` STRING COMMENT 'User or system identifier that created this property record.',
    CONSTRAINT pk_property PRIMARY KEY(`property_id`)
) COMMENT 'Master reference table for property. Referenced by property_id.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`sponsorship`.`inventory_unit` (
    `inventory_unit_id` BIGINT COMMENT 'Primary key for inventory_unit',
    `brand_id` BIGINT COMMENT 'Reference to the entertainment brand or property associated with this inventory unit (e.g., specific show, league, or franchise).',
    `event_type_id` BIGINT COMMENT 'Reference to the type of event where this inventory unit is activated (e.g., weekly show, pay-per-view, live event).',
    `inventory_category_id` BIGINT COMMENT 'Reference to the detailed inventory category taxonomy for advanced classification and reporting.',
    `venue_id` BIGINT COMMENT 'Reference to the venue where this inventory unit is located for venue-based sponsorship assets.',
    `parent_inventory_unit_id` BIGINT COMMENT 'Self-referencing FK on inventory_unit (parent_inventory_unit_id)',
    `base_rate_amount` DECIMAL(18,2) COMMENT 'Standard list price for this inventory unit before discounts or package pricing.',
    `inventory_unit_category` STRING COMMENT 'High-level category grouping for the inventory unit used for portfolio management and reporting.',
    `cost_per_thousand_cpm` DECIMAL(18,2) COMMENT 'Cost per thousand impressions metric used for media buying comparisons and sponsor ROI analysis.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this inventory unit record was first created in the system.',
    `demographic_target` STRING COMMENT 'Primary demographic audience segment this inventory unit reaches (e.g., Adults 18-49, Males 25-54).',
    `inventory_unit_description` STRING COMMENT 'Detailed description of the inventory unit including placement, dimensions, duration, and visibility specifications.',
    `duration_seconds` STRING COMMENT 'Length of exposure time in seconds for time-based inventory units (broadcast spots, digital video). Null for static placements.',
    `effective_end_date` DATE COMMENT 'Date when this inventory unit is retired or no longer available for sale. Null for ongoing availability.',
    `effective_start_date` DATE COMMENT 'Date when this inventory unit becomes available for sale and activation.',
    `exclusivity_category` STRING COMMENT 'Industry category for which exclusivity is granted (e.g., Automotive, Financial Services, Telecommunications).',
    `exclusivity_flag` BOOLEAN COMMENT 'Indicates whether this inventory unit offers category exclusivity to the sponsor (true) or allows multiple sponsors (false).',
    `format` STRING COMMENT 'Technical format specification for the inventory unit (e.g., 30-second video spot, 728x90 banner, 10x10 ft signage).',
    `frequency_cap` STRING COMMENT 'Maximum number of times this inventory unit can be activated per event or time period to prevent oversaturation.',
    `geographic_coverage` STRING COMMENT 'Geographic reach scope of the inventory unit for audience measurement and sponsor targeting.',
    `impressions_per_event` STRING COMMENT 'Estimated number of impressions delivered per event occurrence for this inventory unit.',
    `lead_time_days` STRING COMMENT 'Number of days advance notice required for sponsor creative submission and activation of this inventory unit.',
    `maximum_availability_quantity` STRING COMMENT 'Maximum number of units available for sale per time period to maintain inventory scarcity and value.',
    `measurement_method` STRING COMMENT 'Methodology used to measure and report performance of this inventory unit (e.g., Nielsen Ratings, Google Analytics, Manual Count).',
    `minimum_commitment_quantity` STRING COMMENT 'Minimum number of units or activations required for purchase of this inventory unit.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this inventory unit record was last updated.',
    `notes` STRING COMMENT 'Additional notes, restrictions, or special instructions for this inventory unit relevant to sales and fulfillment teams.',
    `package_eligible_flag` BOOLEAN COMMENT 'Indicates whether this inventory unit can be included in bundled sponsorship packages (true) or must be sold standalone (false).',
    `placement_location` STRING COMMENT 'Physical or digital location where the sponsorship asset appears (e.g., Arena North Entrance, Broadcast Overlay, Mobile App Home Screen).',
    `platform` STRING COMMENT 'Primary distribution platform or channel where the inventory unit is delivered.',
    `production_requirements` STRING COMMENT 'Technical specifications and production requirements for sponsor creative assets (file formats, dimensions, lead times).',
    `rate_currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the base rate amount.',
    `rate_unit` STRING COMMENT 'Unit of measure for the base rate pricing (e.g., per event, per season, per thousand impressions).',
    `reach_estimate` STRING COMMENT 'Estimated unique audience reach for this inventory unit across all distribution channels.',
    `seasonality_flag` BOOLEAN COMMENT 'Indicates whether this inventory unit is available year-round (false) or only during specific seasons or events (true).',
    `inventory_unit_status` STRING COMMENT 'Current lifecycle status of the inventory unit indicating availability for sale.',
    `unit_code` STRING COMMENT 'Business identifier code for the inventory unit used in sponsor proposals and contracts.',
    `unit_name` STRING COMMENT 'Human-readable name of the sponsorship inventory unit (e.g., Ring Apron Logo, Broadcast Lower Third, Jersey Patch).',
    `unit_type` STRING COMMENT 'Classification of the inventory unit by media channel or activation type.',
    `visibility_rating` STRING COMMENT 'Qualitative rating of the inventory units prominence and visibility to audiences.',
    CONSTRAINT pk_inventory_unit PRIMARY KEY(`inventory_unit_id`)
) COMMENT 'Master reference table for inventory_unit. Referenced by inventory_unit_id.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`sponsorship`.`brand` (
    `brand_id` BIGINT COMMENT 'Primary key for brand',
    `annual_marketing_budget_usd` DECIMAL(18,2) COMMENT 'Estimated annual marketing budget for the brand in USD. Used for sponsor qualification, deal sizing, and partnership opportunity assessment.',
    `brand_category` STRING COMMENT 'Primary industry category or vertical that the brand operates within. Used for sponsor portfolio segmentation and competitive analysis.',
    `brand_code` STRING COMMENT 'Short alphanumeric code used as an external business identifier for the brand in contracts, activation materials, and reporting systems.',
    `brand_equity_score` DECIMAL(18,2) COMMENT 'Quantitative score representing the brands market strength, consumer perception, and overall equity. Used for partnership valuation and sponsor portfolio optimization.',
    `brand_guidelines_url` STRING COMMENT 'URL to the brands official guidelines document covering logo usage, color specifications, and messaging standards. Used to ensure compliant activation execution.',
    `brand_logo_url` STRING COMMENT 'Web URL pointing to the official brand logo asset used for digital activations, broadcast integrations, and marketing materials.',
    `brand_name` STRING COMMENT 'Official legal or trade name of the brand. This is the primary human-readable identifier used across all sponsorship materials and contracts.',
    `brand_status` STRING COMMENT 'Current lifecycle status of the brand within the sponsorship ecosystem. Active brands have current or recent partnerships; prospective brands are in the sales pipeline.',
    `brand_tier` STRING COMMENT 'Sponsorship tier classification indicating the level of partnership prominence and benefits (e.g., title sponsor, presenting sponsor, official partner).',
    `brand_value_proposition` STRING COMMENT 'Core value proposition or brand positioning statement. Used to align sponsorship activations with brand messaging and ensure partnership authenticity.',
    `brand_website_url` STRING COMMENT 'Official website URL for the brand. Used for sponsor profile pages, activation tracking, and digital partnership integrations.',
    `competitor_brands` STRING COMMENT 'Comma-separated list of direct competitor brand names that must be excluded from partnerships due to category exclusivity. Used for conflict checking and sales pipeline management.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this brand record was first created in the system. Used for data lineage and audit trail purposes.',
    `credit_rating` STRING COMMENT 'Corporate credit rating assigned by major rating agencies (e.g., S&P, Moodys). Used for financial risk assessment and payment terms determination.',
    `exclusivity_category` STRING COMMENT 'Product or service category for which this brand holds exclusive sponsorship rights (e.g., automotive, beverage, financial services). Used to manage category conflicts and competitive separation.',
    `first_partnership_date` DATE COMMENT 'Date when the brand first entered into a sponsorship partnership with the organization. Used for relationship tenure analysis and loyalty tracking.',
    `headquarters_address` STRING COMMENT 'Full street address of the brands corporate headquarters. Used for contract execution, legal correspondence, and corporate relationship tracking.',
    `headquarters_city` STRING COMMENT 'City where the brands corporate headquarters is located. Used for geographic segmentation and regional partnership analysis.',
    `headquarters_country_code` STRING COMMENT 'Three-letter ISO country code for the brands headquarters location. Used for international partnership management and market segmentation.',
    `headquarters_postal_code` STRING COMMENT 'Postal or ZIP code for the brands headquarters address. Used for mailing and geographic analysis.',
    `headquarters_state_province` STRING COMMENT 'State or province where the brands headquarters is located. Used for regional market analysis and compliance tracking.',
    `is_active` BOOLEAN COMMENT 'Boolean flag indicating whether the brand is currently active in the sponsorship ecosystem. True means the brand has active partnerships or is in active sales pipeline; False means inactive or terminated.',
    `last_partnership_date` DATE COMMENT 'Date of the most recent active or completed sponsorship partnership with the brand. Used for recency analysis and reactivation targeting.',
    `legal_entity_type` STRING COMMENT 'Legal structure of the brands parent organization (e.g., corporation, LLC, partnership). Used for contract structuring and compliance requirements.',
    `notes` STRING COMMENT 'Free-form text field for additional notes, special requirements, or contextual information about the brand that does not fit structured fields.',
    `parent_company_name` STRING COMMENT 'Name of the parent corporation or holding company that owns this brand. Used for corporate relationship tracking and consolidated reporting.',
    `payment_terms_days` STRING COMMENT 'Standard number of days allowed for invoice payment (e.g., Net 30, Net 60). Used for cash flow planning and contract negotiation.',
    `preferred_activation_channels` STRING COMMENT 'Comma-separated list of the brands preferred sponsorship activation channels (e.g., broadcast, digital, venue signage, experiential). Used for partnership planning and proposal development.',
    `preferred_currency_code` STRING COMMENT 'Three-letter ISO currency code for the brands preferred transaction currency. Used for contract pricing and invoicing.',
    `primary_contact_email` STRING COMMENT 'Email address of the primary brand contact for sponsorship communications, contract execution, and activation coordination.',
    `primary_contact_name` STRING COMMENT 'Full name of the primary business contact or decision-maker at the brand for sponsorship matters. Used for relationship management and contract negotiations.',
    `primary_contact_phone` STRING COMMENT 'Primary telephone number for the brand contact. Used for urgent communications and relationship management.',
    `social_media_followers_count` BIGINT COMMENT 'Total number of followers across the brands primary social media platforms. Used to assess digital reach and activation amplification potential.',
    `sponsorship_budget_usd` DECIMAL(18,2) COMMENT 'Estimated annual budget allocated specifically for sponsorship investments in USD. Used for deal qualification and portfolio planning.',
    `stock_ticker_symbol` STRING COMMENT 'Public stock exchange ticker symbol for publicly traded parent companies. Used for financial monitoring and market performance tracking.',
    `target_audience_demographic` STRING COMMENT 'Description of the brands primary target consumer demographic (e.g., age range, gender, income level). Used for sponsor-property fit analysis and activation planning.',
    `tax_identification_number` STRING COMMENT 'Corporate tax identification number or employer identification number (EIN). Used for tax reporting, compliance, and contract execution.',
    `total_lifetime_investment_usd` DECIMAL(18,2) COMMENT 'Cumulative total of all sponsorship investments made by the brand across all partnerships to date in USD. Used for sponsor value segmentation and relationship prioritization.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this brand record was last modified. Used for change tracking and data freshness monitoring.',
    CONSTRAINT pk_brand PRIMARY KEY(`brand_id`)
) COMMENT 'Master reference table for brand. Referenced by brand_id.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`sponsorship`.`inventory_category` (
    `inventory_category_id` BIGINT COMMENT 'Primary key for inventory_category',
    `parent_inventory_category_id` BIGINT COMMENT 'Self-referencing FK on inventory_category (parent_inventory_category_id)',
    `approval_authority` STRING COMMENT 'Name of the department, role, or entity responsible for approving sponsor activations in this category (e.g., League Office, Broadcast Standards, Venue Operations). Null if no approval required.',
    `asset_class` STRING COMMENT 'Commercial tier classification indicating the relative value and exclusivity of the inventory category. Premium assets command highest rates and offer maximum visibility; exclusive assets are limited to single sponsors.',
    `audience_reach_type` STRING COMMENT 'Primary audience reach channel for this inventory category: in-venue (live attendees), broadcast (TV/radio), digital (online/mobile), hybrid (multiple channels), or global (worldwide distribution).',
    `base_rate_amount` DECIMAL(18,2) COMMENT 'Standard base rate or list price per unit for this inventory category in USD. Actual deal pricing may vary based on package, term, and negotiation.',
    `category_code` STRING COMMENT 'Short alphanumeric code representing the inventory category (e.g., JERSEY_PATCH, VENUE_SIGNAGE, BROADCAST_SPOT). Used as a business identifier for external references and integrations.',
    `category_level` STRING COMMENT 'Numeric level in the inventory category hierarchy (1 = top level, 2 = sub-category, 3 = detailed category). Supports multi-level classification of sponsorship assets.',
    `category_name` STRING COMMENT 'Full descriptive name of the inventory category (e.g., Jersey Patch Sponsorship, Arena Naming Rights, Broadcast Commercial Slot).',
    `category_restrictions` STRING COMMENT 'Text description of any sponsor category restrictions or exclusions for this inventory (e.g., no alcohol brands, no competing leagues, family-friendly content only).',
    `category_type` STRING COMMENT 'High-level classification of the inventory category based on delivery medium: physical (signage, jerseys), digital (website, social media), broadcast (TV, radio spots), experiential (fan activations), naming_rights (venue, event naming), or hospitality (suite access, VIP experiences).',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this inventory category record was first created in the system.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for base rate pricing (e.g., USD, EUR, GBP).',
    `inventory_category_description` STRING COMMENT 'Detailed business description of the inventory category, including typical use cases, placement specifications, and audience reach characteristics.',
    `effective_end_date` DATE COMMENT 'Date when this inventory category will no longer be available for sale or fulfillment. Null for ongoing categories.',
    `effective_start_date` DATE COMMENT 'Date when this inventory category became or will become available for sale and fulfillment.',
    `estimated_impressions_per_unit` BIGINT COMMENT 'Average number of impressions or exposures generated per unit of inventory in this category. Used for media value calculation and sponsor reporting.',
    `fulfillment_complexity` STRING COMMENT 'Operational complexity level for delivering this inventory category: low (simple digital placement), medium (standard signage), high (custom fabrication), custom (bespoke activations).',
    `is_exclusive` BOOLEAN COMMENT 'Indicates whether this inventory category is sold on an exclusive basis (true) or allows multiple sponsors (false). Exclusive categories typically include naming rights and presenting sponsorships.',
    `is_renewable` BOOLEAN COMMENT 'Indicates whether inventory in this category is typically sold on a renewable basis (true) such as season-long or multi-year deals, or as one-time purchases (false).',
    `lead_time_days` STRING COMMENT 'Number of days advance notice required to activate or fulfill inventory in this category. Critical for production, approval, and installation timelines.',
    `maximum_purchase_quantity` STRING COMMENT 'Maximum number of units available or allowed for purchase in this inventory category. Null if unlimited or not applicable.',
    `measurement_unit` STRING COMMENT 'Standard unit of measure for quantifying inventory in this category (e.g., impressions for digital, spots for broadcast, square feet for signage, seconds for video).',
    `minimum_purchase_quantity` STRING COMMENT 'Minimum number of units that must be purchased for this inventory category. Null if no minimum applies.',
    `modified_by` STRING COMMENT 'Username or identifier of the user who last modified this inventory category record.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this inventory category record was last modified.',
    `notes` STRING COMMENT 'Free-form text field for additional notes, special instructions, or internal comments about this inventory category.',
    `parent_category_id` BIGINT COMMENT 'Reference to the parent inventory category in a hierarchical classification structure. Null for top-level categories.',
    `performance_metric_type` STRING COMMENT 'Primary performance metric used to measure and report effectiveness of this inventory category (e.g., CPM, GRP, engagement rate, brand lift, ROI). [ENUM-REF-CANDIDATE: cpm|grp|reach|frequency|engagement_rate|click_through_rate|brand_lift|conversion_rate|roi — promote to reference product]',
    `reporting_frequency` STRING COMMENT 'Standard frequency for delivering performance reports to sponsors for this inventory category.',
    `requires_approval` BOOLEAN COMMENT 'Indicates whether sponsor creative or activation plans for this inventory category require league, venue, or broadcast partner approval before execution.',
    `sales_channel` STRING COMMENT 'Primary sales channel through which this inventory category is typically sold: direct (internal sales team), agency (through advertising agencies), marketplace (programmatic/self-service), or partnership (co-sold with partners).',
    `inventory_category_status` STRING COMMENT 'Current lifecycle status of the inventory category. Active categories are available for sale and fulfillment; inactive categories are temporarily unavailable; deprecated categories are phased out; pending_approval categories await commercial approval.',
    `typical_contract_term_months` STRING COMMENT 'Standard contract duration in months for this inventory category. Null if not applicable or highly variable.',
    `venue_type` STRING COMMENT 'Type of venue or platform where this inventory category is typically delivered. Null for non-venue-specific categories.',
    `created_by` STRING COMMENT 'Username or identifier of the user who created this inventory category record.',
    CONSTRAINT pk_inventory_category PRIMARY KEY(`inventory_category_id`)
) COMMENT 'Master reference table for inventory_category. Referenced by inventory_category_id.';

